import * as React from 'react';
import { Text } from '../../text';
import type { StyleProps } from '../../util/types';
import type { FileProps } from './interface';

export const FileName = ({
  file,
  nameRenderer,
  ...styleProps
}: Pick<FileProps, 'nameRenderer' | 'file'> & StyleProps) => {
  if (nameRenderer) {
    return nameRenderer(file);
  }
  return (
    <Text as="div" lineClamp={1} {...styleProps}>
      {file.name}
    </Text>
  );
};
